interface.signature:
interface StepHandler {
  executeStep(
    step: WorkflowStep,
    context: ExecutionContext,
    userInput?: unknown
  ): Promise<StepResult>;
}

interface StepResult {
  output: Record<string, unknown>;
  nextStepNumber: number | null;
  requiresUserInput: boolean;
}

class Agent {
  constructor(config: {
    name: string;
    instructions: string;
    model: AI;
    tools?: Record<string, Tool>;
  })

  async stream(messages: Message[]): AsyncGenerator<Message>
  async generate(messages: Message[]): Promise<Message>
}

class AxACE {
  constructor(config: {
    studentAI: AxAI;
    teacherAI: AxAI;
  }, options?: { initialPlaybook?: Playbook })

  async compile(program, examples, metric): Promise<OptimizationResult>
  async applyOnlineUpdate(update: { example, prediction, feedback }): Promise<CuratorDelta>
  getPlaybook(): Playbook
}

export const workflowRouter = t.router({ startExecution: t.procedure .input(z.object({ workflowId: z.string(), ... })) .mutation(async ({ input, ctx }) => { ... }),
submitStepInput: t.procedure .input(z.object({ executionId: z.string(), userInput: z.unknown() })) .mutation(async ({ input, ctx }) => { ... }),
approveToolCall: t.procedure .input(z.object({ executionId: z.string(), toolName: z.string() })) .mutation(async ({ input, ctx }) => { ... }),
rejectToolCall: t.procedure .input(z.object({ executionId: z.string(), toolName: z.string(), feedback: z.string() })) .mutation(async ({ input, ctx }) => { ... }) });
